public class Solution {
    public int maxSubArray(int[] nums) {
        int max = nums[0];
        int sum = 0;
        for (int x : nums) {
            sum += x;
            max = Math.max(max, sum);
            if (sum < 0) sum = 0;
        }
        return max;
    }
}

