class Solution:
    def maxSubArray(self, nums: List[int]) -> int:
        max_sum = nums[0]
        cur_sum = 0
        for x in nums:
            cur_sum += x
            max_sum = max(max_sum, cur_sum)
            if cur_sum < 0: cur_sum = 0
        return max_sum

